  1→/**
  2→ * Orchestrator HTTP route handlers.
  3→ *
  4→ * Pure request->response mappings that delegate to session-lifecycle functions
  5→ * injected via OrchestratorRouteDeps. No direct DB or IO access.
  6→ */
  7→import { jsonError, jsonResponse } from "../http/response";
  8→import { withRequestLogging, type RouteHandler } from "../http/request-logging";
  9→import type {
 10→  OrchestratorSessionResult,
 11→  SessionStatusResult,
 12→  AbortSessionResult,
 13→  AcceptSessionResult,
 14→  ReviewResult,
 15→  RejectSessionResult,
 16→  PromptSessionResult,
 17→} from "./session-lifecycle";
 18→import type { SseRegistry } from "../streaming/sse-registry";
 19→
 20→// ---------------------------------------------------------------------------
 21→// Port: Dependencies as function signatures
 22→// ---------------------------------------------------------------------------
 23→
 24→export type OrchestratorRouteDeps = {
 25→  createSession: (
 26→    workspaceId: string,
 27→    taskId: string,
 28→    authToken: string,
 29→  ) => Promise<OrchestratorSessionResult>;
 30→  getSessionStatus: (sessionId: string) => Promise<SessionStatusResult>;
 31→  abortSession: (sessionId: string) => Promise<AbortSessionResult>;
 32→  acceptSession: (
 33→    sessionId: string,
 34→    summary: string,
 35→  ) => Promise<AcceptSessionResult>;
 36→  getReview: (sessionId: string) => Promise<ReviewResult>;
 37→  rejectSession: (
 38→    sessionId: string,
 39→    feedback: string,
 40→  ) => Promise<RejectSessionResult>;
 41→  sendPrompt: (
 42→    sessionId: string,
 43→    text: string,
 44→  ) => Promise<PromptSessionResult>;
 45→};
 46→
 47→// ---------------------------------------------------------------------------
 48→// Request body parsing
 49→// ---------------------------------------------------------------------------
 50→
 51→type AssignBody = { taskId?: string };
 52→type AcceptBody = { summary?: string };
 53→type RejectBody = { feedback?: string };
 54→type PromptBody = { text?: string };
 55→
 56→async function parseJsonBody<T>(request: Request): Promise<T | undefined> {
 57→  try {
 58→    return (await request.json()) as T;
 59→  } catch {
 60→    return undefined;
 61→  }
 62→}
 63→
 64→function extractAuthToken(request: Request): string {
 65→  return request.headers.get("Cookie") ?? "";
 66→}
 67→
 68→// ---------------------------------------------------------------------------
 69→// Response builders (pure)
 70→// ---------------------------------------------------------------------------
 71→
 72→function assignResponse(
 73→  workspaceId: string,
 74→  value: { agentSessionId: string; streamId: string; worktreeBranch: string },
 75→): Response {
 76→  return jsonResponse(
 77→    {
 78→      agentSessionId: value.agentSessionId,
 79→      streamId: value.streamId,
 80→      streamUrl: `/api/orchestrator/${workspaceId}/sessions/${value.agentSessionId}/stream`,
 81→    },
 82→    200,
 83→  );
 84→}
 85→
 86→function pickDefined<T extends Record<string, unknown>>(obj: T): Partial<T> {
 87→  const result: Record<string, unknown> = {};
 88→  for (const [key, value] of Object.entries(obj)) {
 89→    if (value !== undefined) {
 90→      result[key] = value;
 91→    }
 92→  }
 93→  return result as Partial<T>;
 94→}
 95→
 96→function statusResponse(
 97→  sessionId: string,
 98→  value: {
 99→    orchestratorStatus: string;
100→    worktreeBranch?: string;
101→    worktreePath?: string;
102→    startedAt?: string;
103→    lastEventAt?: string;
104→    error?: string;
105→  },
106→): Response {
107→  return jsonResponse(
108→    {
109→      agentSessionId: sessionId,
110→      orchestratorStatus: value.orchestratorStatus,
111→      ...pickDefined({
112→        worktreeBranch: value.worktreeBranch,
113→        worktreePath: value.worktreePath,
114→        startedAt: value.startedAt,
115→        lastEventAt: value.lastEventAt,
116→        error: value.error,
117→      }),
118→    },
119→    200,
120→  );
121→}
122→
123→function acceptResponse(): Response {
124→  return jsonResponse({ accepted: true, taskStatus: "done" }, 200);
125→}
126→
127→function abortResponse(): Response {
128→  return jsonResponse({ aborted: true, taskStatus: "ready" }, 200);
129→}
130→
131→function reviewResponse(value: {
132→  taskTitle: string;
133→  diff: unknown;
134→  session: unknown;
135→}): Response {
136→  return jsonResponse(value, 200);
137→}
138→
139→function rejectResponse(): Response {
140→  return jsonResponse({ rejected: true, continuing: true }, 200);
141→}
142→
143→function promptResponse(): Response {
144→  return jsonResponse({ delivered: true }, 202);
145→}
146→
147→function sessionErrorResponse(error: {
148→  message: string;
149→  httpStatus: number;
150→}): Response {
151→  return jsonError(error.message, error.httpStatus);
152→}
153→
154→// ---------------------------------------------------------------------------
155→// Route handler factory
156→// ---------------------------------------------------------------------------
157→
158→export function createOrchestratorRouteHandlers(deps: OrchestratorRouteDeps) {
159→  const assign: RouteHandler = async (request) => {
160→    const workspaceId = request.params.workspaceId;
161→    const body = await parseJsonBody<AssignBody>(request);
162→
163→    if (!body?.taskId) {
164→      return jsonError("taskId is required", 400);
165→    }
166→
167→    const authToken = extractAuthToken(request);
168→    const result = await deps.createSession(workspaceId, body.taskId, authToken);
169→
170→    if (!result.ok) {
171→      return sessionErrorResponse(result.error);
172→    }
173→
174→    return assignResponse(workspaceId, result.value);
175→  };
176→
177→  const status: RouteHandler = async (request) => {
178→    const sessionId = request.params.sessionId;
179→    const result = await deps.getSessionStatus(sessionId);
180→
181→    if (!result.ok) {
182→      return sessionErrorResponse(result.error);
183→    }
184→
185→    return statusResponse(sessionId, result.value);
186→  };
187→
188→  const accept: RouteHandler = async (request) => {
189→    const sessionId = request.params.sessionId;
190→    const body = await parseJsonBody<AcceptBody>(request);
191→    const summary = body?.summary ?? "";
192→
193→    const result = await deps.acceptSession(sessionId, summary);
194→
195→    if (!result.ok) {
196→      return sessionErrorResponse(result.error);
197→    }
198→
199→    return acceptResponse();
200→  };
201→
202→  const abort: RouteHandler = async (request) => {
203→    const sessionId = request.params.sessionId;
204→    const result = await deps.abortSession(sessionId);
205→
206→    if (!result.ok) {
207→      return sessionErrorResponse(result.error);
208→    }
209→
210→    return abortResponse();
211→  };
212→
213→  const review: RouteHandler = async (request) => {
214→    const sessionId = request.params.sessionId;
215→    const result = await deps.getReview(sessionId);
216→
217→    if (!result.ok) {
218→      return sessionErrorResponse(result.error);
219→    }
220→
221→    return reviewResponse(result.value);
222→  };
223→
224→  const reject: RouteHandler = async (request) => {
225→    const sessionId = request.params.sessionId;
226→    const body = await parseJsonBody<RejectBody>(request);
227→
228→    if (!body?.feedback || body.feedback.trim() === "") {
229→      return jsonError("feedback is required", 400);
230→    }
231→
232→    const result = await deps.rejectSession(sessionId, body.feedback);
233→
234→    if (!result.ok) {
235→      return sessionErrorResponse(result.error);
236→    }
237→
238→    return rejectResponse();
239→  };
240→
241→  const prompt: RouteHandler = async (request) => {
242→    const sessionId = request.params.sessionId;
243→    const body = await parseJsonBody<PromptBody>(request);
244→
245→    if (!body?.text || body.text.trim() === "") {
246→      return jsonError("text is required", 400);
247→    }
248→
249→    const result = await deps.sendPrompt(sessionId, body.text);
250→
251→    if (!result.ok) {
252→      return sessionErrorResponse(result.error);
253→    }
254→
255→    return promptResponse();
256→  };
257→
258→  return { assign, status, accept, abort, review, reject, prompt };
259→}
260→
261→// ---------------------------------------------------------------------------
262→// SSE stream route handler factory
263→// ---------------------------------------------------------------------------
264→
265→export type StreamRouteDeps = {
266→  sseRegistry: SseRegistry;
267→};
268→
269→export function createStreamRouteHandler(deps: StreamRouteDeps) {
270→  const stream: RouteHandler = async (request) => {
271→    const sessionId = request.params.sessionId;
272→
273→    if (!sessionId) {
274→      return jsonError("sessionId is required", 400);
275→    }
276→
277→    const streamId = `stream-${sessionId}`;
278→    return deps.sseRegistry.handleStreamRequest(streamId);
279→  };
280→
281→  return { stream };
282→}
283→
284→// ---------------------------------------------------------------------------
285→// Wiring factory: creates OrchestratorRouteDeps from server dependencies
286→// ---------------------------------------------------------------------------
287→
288→export type OrchestratorWiringDeps = {
289→  surreal: import("surrealdb").Surreal;
290→  shellExec: import("./worktree-manager").ShellExec;
291→  brainBaseUrl: string;
292→  sseRegistry?: SseRegistry;
293→  queryFn: import("./spawn-agent").QueryFn;
294→  auth: { api: { getSession: (opts: { headers: Headers }) => Promise<{ user?: { id?: string } } | null> } };
295→};
296→
297→export function wireOrchestratorRoutes(
298→  wiringDeps: OrchestratorWiringDeps,
299→): {
300→  assign: RouteHandler;
301→  status: RouteHandler;
302→  accept: RouteHandler;
303→  abort: RouteHandler;
304→  review: RouteHandler;
305→  reject: RouteHandler;
306→  prompt: RouteHandler;
307→  stream?: RouteHandler;
308→} {
309→  // Workspace access guard — resolves user from session cookie, checks membership
310→  const validateWorkspaceAccess = async (request: Request, workspaceId: string): Promise<Response | undefined> => {
311→    const session = await wiringDeps.auth.api.getSession({ headers: request.headers });
312→    if (!session?.user?.id) {
313→      return jsonError("authentication required", 401);
314→    }
315→    const { RecordId } = await import("surrealdb");
316→    const personRecord = new RecordId("person", session.user.id);
317→    const workspaceRecord = new RecordId("workspace", workspaceId);
318→    // member_of is identity->workspace; resolve person->identity via identity_person subquery
319→    const [memberRows] = await wiringDeps.surreal.query<[Array<{ role: string }>]>(
320→      `SELECT role FROM member_of WHERE in IN (SELECT VALUE in FROM identity_person WHERE out = $person) AND out = $ws LIMIT 1;`,
321→      { person: personRecord, ws: workspaceRecord },
322→    );
323→    if (!memberRows || memberRows.length === 0) {
324→      return jsonError("not a member of this workspace", 403);
325→    }
326→    return undefined;
327→  };
328→
329→  // Lazy imports to keep module boundary clean
330→  const lifecycleImport = import("./session-lifecycle");
331→  const queriesImport = import("../mcp/mcp-queries");
332→  const guardImport = import("./assignment-guard");
333→  const stallDetectorImport = import("./stall-detector");
334→
335→  // Helper: resolve repo_path from workspace record
336→  const resolveRepoRoot = async (workspaceRecord: import("surrealdb").RecordId<"workspace", string>): Promise<string> => {
337→    const [rows] = await wiringDeps.surreal.query<[Array<{ repo_path?: string }>]>(
338→      `SELECT repo_path FROM $ws;`,
339→      { ws: workspaceRecord },
340→    );
341→    const repoPath = rows[0]?.repo_path;
342→    if (!repoPath) {
343→      throw new Error(`Workspace ${workspaceRecord.id} has no repo_path configured`);
344→    }
345→    return repoPath;
346→  };
347→
348→  // Use mock spawn for acceptance tests, production spawn otherwise
349→  const spawnAgentImport = process.env.ORCHESTRATOR_MOCK_AGENT === "true"
350→    ? Promise.resolve({
351→        createSpawnAgent: (_qfn: import("./spawn-agent").QueryFn): import("./spawn-agent").SpawnAgentFn =>
352→          () => ({
353→            messages: (async function* () {})(),
354→            abort: () => {},
355→          }),
356→      })
357→    : import("./spawn-agent");
358→
359→  const routeDeps: OrchestratorRouteDeps = {
360→    createSession: async (workspaceId, taskId, authToken) => {
361→      const [lifecycle, queries, guard, { createSpawnAgent }, stallDetector] = await Promise.all([
362→        lifecycleImport,
363→        queriesImport,
364→        guardImport,
365→        spawnAgentImport,
366→        stallDetectorImport,
367→      ]);
368→      const spawnAgent = createSpawnAgent(wiringDeps.queryFn);
369→      const result = await lifecycle.createOrchestratorSession({
370→        surreal: wiringDeps.surreal,
371→        shellExec: wiringDeps.shellExec,
372→        brainBaseUrl: wiringDeps.brainBaseUrl,
373→        workspaceId,
374→        taskId,
375→        authToken,
376→        validateAssignment: guard.validateAssignment,
377→        createAgentSession: queries.createAgentSession,
378→        spawnAgent,
379→      });
380→
381→      // Wire SSE stream + event iteration on success
382→      if (result.ok && wiringDeps.sseRegistry) {
383→        const { agentSessionId, streamId } = result.value;
384→        wiringDeps.sseRegistry.registerMessage(streamId);
385→
386→        const handle = lifecycle.getHandle(agentSessionId);
387→        if (handle) {
388→          const { RecordId } = await import("surrealdb");
389→          lifecycle.startEventIteration(
390→            {
391→              emitEvent: wiringDeps.sseRegistry.emitEvent,
392→              updateSessionStatus: async (sid, status, error) => {
393→                const rec = new RecordId("agent_session", sid);
394→                await wiringDeps.surreal.update(rec).merge({
395→                  orchestrator_status: status,
396→                  ...(error !== undefined ? { error } : {}),
397→                });
398→              },
399→              updateLastEventAt: async (sid) => {
400→                const rec = new RecordId("agent_session", sid);
401→                await wiringDeps.surreal.update(rec).merge({
402→                  last_event_at: new Date(),
403→                });
404→              },
405→              getSessionStatus: async (sid) => {
406→                const rec = new RecordId("agent_session", sid);
407→                const row = await wiringDeps.surreal.select(rec) as { orchestrator_status?: string } | undefined;
408→                return (row?.orchestrator_status ?? "error") as import("./types").OrchestratorStatus;
409→              },
410→              startStallDetector: (sid, stId) =>
411→                stallDetector.startStallDetector(
412→                  {
413→                    abortSession: async (abortSid) => {
414→                      const abortResult = await lifecycle.abortOrchestratorSession({
415→                        surreal: wiringDeps.surreal,
416→                        shellExec: wiringDeps.shellExec,
417→                        resolveRepoRoot,
418→                        sessionId: abortSid,
419→                        endAgentSession: queries.endAgentSession,
420→                      });
421→                      return abortResult;
422→                    },
423→                    createObservation: async () => {},
424→                    emitEvent: wiringDeps.sseRegistry!.emitEvent,
425→                  },
426→                  stallDetector.DEFAULT_STALL_CONFIG,
427→                  sid,
428→                  stId,
429→                ),
430→            },
431→            handle.messages,
432→            streamId,
433→            agentSessionId,
434→          );
435→        }
436→      }
437→
438→      return result;
439→    },
440→
441→    getSessionStatus: async (sessionId) => {
442→      const lifecycle = await lifecycleImport;
443→      return lifecycle.getOrchestratorSessionStatus({
444→        surreal: wiringDeps.surreal,
445→        sessionId,
446→      });
447→    },
448→
449→    abortSession: async (sessionId) => {
450→      const [lifecycle, queries] = await Promise.all([
451→        lifecycleImport,
452→        queriesImport,
453→      ]);
454→      return lifecycle.abortOrchestratorSession({
455→        surreal: wiringDeps.surreal,
456→        shellExec: wiringDeps.shellExec,
457→        resolveRepoRoot,
458→        sessionId,
459→        endAgentSession: queries.endAgentSession,
460→      });
461→    },
462→
463→    acceptSession: async (sessionId, summary) => {
464→      const [lifecycle, queries] = await Promise.all([
465→        lifecycleImport,
466→        queriesImport,
467→      ]);
468→      return lifecycle.acceptOrchestratorSession({
469→        surreal: wiringDeps.surreal,
470→        sessionId,
471→        summary,
472→        endAgentSession: queries.endAgentSession,
473→      });
474→    },
475→
476→    getReview: async (sessionId) => {
477→      const [lifecycle, worktreeManager] = await Promise.all([
478→        lifecycleImport,
479→        import("./worktree-manager"),
480→      ]);
481→      return lifecycle.getOrchestratorReview({
482→        surreal: wiringDeps.surreal,
483→        sessionId,
484→        resolveRepoRoot,
485→        getDiff: (repoRoot: string, branchName: string) =>
486→          worktreeManager.getDiff(wiringDeps.shellExec, repoRoot, branchName),
487→        getTaskTitle: async (taskId: string) => {
488→          const { RecordId } = await import("surrealdb");
489→          const taskRecord = new RecordId("task", taskId);
490→          const rows = (await wiringDeps.surreal.query(
491→            `SELECT title FROM $task;`,
492→            { task: taskRecord },
493→          )) as Array<Array<{ title: string }>>;
494→          return rows[0]?.[0]?.title ?? "";
495→        },
496→      });
497→    },
498→
499→    rejectSession: async (sessionId, feedback) => {
500→      const lifecycle = await lifecycleImport;
501→      return lifecycle.rejectOrchestratorSession({
502→        surreal: wiringDeps.surreal,
503→        sessionId,
504→        feedback,
505→      });
506→    },
507→
508→    sendPrompt: async (sessionId, text) => {
509→      const lifecycle = await lifecycleImport;
510→      return lifecycle.sendSessionPrompt({
511→        surreal: wiringDeps.surreal,
512→        sessionId,
513→        text,
514→      });
515→    },
516→  };
517→
518→  const handlers = createOrchestratorRouteHandlers(routeDeps);
519→
520→  // Wrap handler with workspace access check
521→  const withWorkspaceAccess = (handler: RouteHandler): RouteHandler => async (request) => {
522→    const workspaceId = request.params.workspaceId;
523→    if (workspaceId) {
524→      const accessError = await validateWorkspaceAccess(request, workspaceId);
525→      if (accessError) return accessError;
526→    }
527→    return handler(request);
528→  };
529→
530→  const streamHandler = wiringDeps.sseRegistry
531→    ? createStreamRouteHandler({ sseRegistry: wiringDeps.sseRegistry })
532→    : undefined;
533→
534→  return {
535→    assign: withRequestLogging("orchestrator.assign", "POST", withWorkspaceAccess(handlers.assign)),
536→    status: withRequestLogging("orchestrator.status", "GET", withWorkspaceAccess(handlers.status)),
537→    accept: withRequestLogging("orchestrator.accept", "POST", withWorkspaceAccess(handlers.accept)),
538→    abort: withRequestLogging("orchestrator.abort", "POST", withWorkspaceAccess(handlers.abort)),
539→    review: withRequestLogging("orchestrator.review", "GET", withWorkspaceAccess(handlers.review)),
540→    reject: withRequestLogging("orchestrator.reject", "POST", withWorkspaceAccess(handlers.reject)),
541→    prompt: withRequestLogging("orchestrator.prompt", "POST", withWorkspaceAccess(handlers.prompt)),
542→    ...(streamHandler
543→      ? { stream: withRequestLogging("orchestrator.stream", "GET", withWorkspaceAccess(streamHandler.stream)) }
544→      : {}),
545→  };
546→}
547→

