268→  | { ok: false; error: SessionError };
269→
270→async function lookupSession(
271→  surreal: Surreal,
272→  sessionId: string,
273→): Promise<SessionLookup> {
274→  const record = new RecordId("agent_session", sessionId);
275→  const session = await surreal.select<SessionRow>(record);
276→  if (!session) {
277→    return { ok: false, error: sessionNotFound(sessionId) };
278→  }
279→  if (!session.orchestrator_status) {
280→    throw new Error(`agent_session ${sessionId} missing orchestrator_status — data corruption`);
281→  }
282→  const status = session.orchestrator_status as OrchestratorStatus;
283→  return { ok: true, session, record, status };
284→}
285→
286→function requireWorkspace(session: SessionRow, sessionId: string): RecordId<"workspace", string> {
287→  if (!session.workspace) {
288→    throw new Error(`agent_session ${sessionId} missing workspace — data corruption`);
289→  }
290→  return session.workspace as RecordId<"workspace", string>;
291→}
292→
293→function generateStreamId(sessionId: string): string {
294→  return `stream-${sessionId}`;
295→}
296→
297→function slugFromTitle(title: string): string {
298→  return title
299→    .toLowerCase()
300→    .replace(/[^a-z0-9]+/g, "-")
301→    .replace(/^-|-$/g, "")
302→    .slice(0, 50);
303→}
304→
305→// ---------------------------------------------------------------------------
306→// createOrchestratorSession
307→// ---------------------------------------------------------------------------
308→
309→type CreateSessionInput = {
310→  surreal: Surreal;
311→  shellExec: ShellExec;
312→  brainBaseUrl: string;
313→  workspaceId: string;
314→  taskId: string;
315→  intentId?: string;
316→  authToken?: string;
317→  spawnAgent?: SpawnAgentFn;
318→  validateAssignment: (
319→    surreal: Surreal,
320→    workspaceId: string,
321→    taskId: string,
322→  ) => Promise<AssignmentResult>;
323→  createAgentSession: (input: {
324→    surreal: Surreal;
325→    agent: string;
326→    workspaceRecord: RecordId<"workspace", string>;
327→    taskId?: string;
328→  }) => Promise<{ session_id: string }>;
329→};
330→
331→export async function createOrchestratorSession(
332→  input: CreateSessionInput,
333→): Promise<OrchestratorSessionResult> {
334→  // 0. Intent authorization gate (optional — backwards compatible)
335→  if (input.intentId) {
336→    const gateResult = await checkIntentAuthorization(input.surreal, input.intentId, input.workspaceId);
337→    if (!gateResult.ok) {
338→      return { ok: false, error: gateResult.error };
339→    }
340→  }
341→
342→  // 1. Validate assignment eligibility
343→  const assignmentResult = await input.validateAssignment(
344→    input.surreal,
345→    input.workspaceId,
346→    input.taskId,
347→  );
348→
349→  if (!assignmentResult.ok) {
350→    return { ok: false, error: fromAssignmentError(assignmentResult.error) };
351→  }
352→
353→  const { validation } = assignmentResult;
354→  const taskSlug = `${slugFromTitle(validation.title)}-${crypto.randomUUID()}`;
355→  const repoRoot = validation.repoPath;
356→
357→  // 2. Create worktree
358→  const worktreeResult = await createWorktree(
359→    input.shellExec,
360→    repoRoot,
361→    taskSlug,
362→  );
363→
364→  if (!worktreeResult.ok) {
365→    return {
366→      ok: false,
367→      error: worktreeError(worktreeResult.error.message),
368→    };
369→  }
370→
371→  const { branchName, worktreePath } = worktreeResult.value;
372→
373→  // 3. Create agent_session record
374→  const { session_id: agentSessionId } = await input.createAgentSession({
375→    surreal: input.surreal,
376→    agent: "claude-agent-sdk",
377→    workspaceRecord: validation.workspaceRecord,
378→    taskId: input.taskId,
379→  });
380→
381→  const streamId = generateStreamId(agentSessionId);
382→
383→  // 4. Build config and spawn agent
384→  const agentSpawnConfig: AgentSpawnConfig = {
385→    prompt: `/brain-start-task ${input.taskId}`,
386→    workDir: worktreePath,
387→    workspaceId: input.workspaceId,
388→    brainBaseUrl: input.brainBaseUrl,
389→  };
390→
391→  const spawnFn = input.spawnAgent ?? defaultSpawnAgent;
392→  let handle: AgentHandle;
393→  try {
394→    handle = spawnFn(agentSpawnConfig);
395→  } catch (err) {
396→    // Rollback: remove worktree and delete agent_session on spawn failure
397→    await removeWorktree(input.shellExec, repoRoot, branchName);
398→    const sessionRecord = new RecordId("agent_session", agentSessionId);
399→    await input.surreal.delete(sessionRecord);
400→    return {
401→      ok: false,
402→      error: worktreeError(`Failed to spawn agent: ${err instanceof Error ? err.message : String(err)}`),
403→    };
404→  }
405→
406→  // 5. Register handle for later abort
407→  handleRegistry.set(agentSessionId, handle);
408→
409→  // 6. Update agent_session with orchestrator fields
410→  const sessionRecord = new RecordId("agent_session", agentSessionId);
411→  await input.surreal.update(sessionRecord).merge({
412→    orchestrator_status: "spawning" as OrchestratorStatus,
413→    worktree_branch: branchName,
414→    worktree_path: worktreePath,
415→    stream_id: streamId,
416→  });
417→
418→  // 7. Transition intent to executing and create gates relation
419→  if (input.intentId) {
420→    await transitionIntentToExecuting(input.surreal, input.intentId, sessionRecord);
421→  }
422→
423→  return {
424→    ok: true,
425→    value: {
426→      agentSessionId,
427→      streamId,
428→      worktreeBranch: branchName,
429→    },
430→  };
431→}
432→
433→// ---------------------------------------------------------------------------
434→// Intent authorization helpers
435→// ---------------------------------------------------------------------------
436→
437→async function checkIntentAuthorization(
438→  surreal: Surreal,
439→  intentId: string,
440→  workspaceId: string,
441→): Promise<SessionResult<void>> {
442→  const intent = await getIntentById(surreal, intentId);
443→  if (!intent) {
444→    return {
445→      ok: false,
446→      error: {
447→        code: "INTENT_NOT_AUTHORIZED",
448→        message: `Intent ${intentId} not found`,
449→        httpStatus: 404,
450→      },
451→    };
452→  }
453→
454→  // Validate workspace scope: intent must belong to the session's workspace
455→  const intentWorkspaceId = intent.workspace.id as string;
456→  if (intentWorkspaceId !== workspaceId) {
457→    return {
458→      ok: false,
459→      error: {
460→        code: "WORKSPACE_MISMATCH",
461→        message: `Intent ${intentId} belongs to workspace "${intentWorkspaceId}", not "${workspaceId}"`,
462→        httpStatus: 403,
463→      },
464→    };
465→  }
466→
467→  const status = intent.status as IntentStatus;
468→  if (status !== "authorized") {
469→    return {
470→      ok: false,
471→      error: {
472→        code: "INTENT_NOT_AUTHORIZED",
473→        message: `Intent ${intentId} has status "${status}", expected "authorized"`,
474→        httpStatus: 403,
475→      },
476→    };
477→  }
478→
479→  return { ok: true, value: undefined as void };
480→}
481→
482→async function transitionIntentToExecuting(
483→  surreal: Surreal,
484→  intentId: string,
485→  sessionRecord: RecordId<"agent_session", string>,
486→): Promise<void> {
487→  await updateIntentStatus(surreal, intentId, "executing");
488→
489→  const intentRecord = new RecordId("intent", intentId);
490→  // NOTE: `$session` is a SurrealDB protected variable — use `$sess` instead
491→  await surreal.query(
492→    "RELATE $intent->gates->$sess SET created_at = time::now();",
493→    { intent: intentRecord, sess: sessionRecord },
494→  );
495→
496→  logInfo("orchestrator.intent-gate", "Intent transitioned to executing with gates relation", {
497→    intentId,
498→    sessionId: sessionRecord.id as string,
499→  });
500→}
501→
502→// Default spawn -- placeholder for production use
503→function defaultSpawnAgent(
504→  _config: AgentSpawnConfig,
505→): AgentHandle {
506→  throw new Error(
507→    "spawnAgent not provided -- must be injected for production use",
508→  );
509→}
510→
511→// ---------------------------------------------------------------------------
512→// getOrchestratorSessionStatus
513→// ---------------------------------------------------------------------------
514→
515→type GetStatusInput = {
516→  surreal: Surreal;
517→  sessionId: string;
518→};
519→
520→export async function getOrchestratorSessionStatus(
521→  input: GetStatusInput,
522→): Promise<SessionStatusResult> {
523→  const lookup = await lookupSession(input.surreal, input.sessionId);
524→  if (!lookup.ok) {
525→    return { ok: false, error: lookup.error };
526→  }
527→  const { session } = lookup;
528→
529→  return {
530→    ok: true,
531→    value: {
532→      orchestratorStatus: lookup.status,
533→      ...pickDefined({
534→        worktreeBranch: session.worktree_branch,
535→        worktreePath: session.worktree_path,
536→        startedAt: session.started_at,
537→        lastEventAt: session.last_event_at,
538→        error: session.error,
539→      }),
540→    },
541→  };
542→}
543→
544→// ---------------------------------------------------------------------------
545→// abortOrchestratorSession
546→// ---------------------------------------------------------------------------
547→
548→type AbortSessionInput = {
549→  surreal: Surreal;
550→  shellExec: ShellExec;
551→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
552→  sessionId: string;
553→  endAgentSession: (input: {
554→    surreal: Surreal;
555→    workspaceRecord: RecordId<"workspace", string>;
556→    sessionId: string;
557→    summary: string;
558→  }) => Promise<{ session_id: string; ended: boolean }>;
559→};
560→
561→export async function abortOrchestratorSession(
562→  input: AbortSessionInput,
563→): Promise<AbortSessionResult> {
564→  const lookup = await lookupSession(input.surreal, input.sessionId);
565→  if (!lookup.ok) {
566→    return { ok: false, error: lookup.error };
567→  }
568→  const { session, record: sessionRecord } = lookup;
569→
570→  // 1. Abort the agent process if handle exists
571→  const handle = handleRegistry.get(input.sessionId);
572→  if (handle) {
573→    handle.abort();
574→    handleRegistry.delete(input.sessionId);
575→  }
576→
577→  // 2. Update orchestrator_status to aborted
578→  await input.surreal.update(sessionRecord).merge({
579→    orchestrator_status: "aborted" as OrchestratorStatus,
580→  });
581→
582→  const workspaceRecord = requireWorkspace(session, input.sessionId);
583→
584→  // 3. Remove worktree if branch name exists
585→  if (session.worktree_branch) {
586→    const repoRoot = await input.resolveRepoRoot(workspaceRecord);
587→    await removeWorktree(input.shellExec, repoRoot, session.worktree_branch);
588→  }
589→
590→  // 4. Return task to ready
591→  if (session.task_id) {
592→    await input.surreal.update(session.task_id).merge({
593→      status: "ready",
594→      updated_at: new Date(),
595→    });
596→  }
597→
598→  // 5. End the agent session
599→  await input.endAgentSession({
600→    surreal: input.surreal,
601→    workspaceRecord,
602→    sessionId: input.sessionId,
603→    summary: "Session aborted",
604→  });
605→
606→  return {
607→    ok: true,
608→    value: {
609→      aborted: true,
610→      sessionId: input.sessionId,
611→    },
612→  };
613→}
614→
615→// ---------------------------------------------------------------------------
616→// acceptOrchestratorSession
617→// ---------------------------------------------------------------------------
618→
619→type AcceptSessionInput = {
620→  surreal: Surreal;
621→  sessionId: string;
622→  summary: string;
623→  endAgentSession: (input: {
624→    surreal: Surreal;
625→    workspaceRecord: RecordId<"workspace", string>;
626→    sessionId: string;
627→    summary: string;
628→  }) => Promise<{ session_id: string; ended: boolean }>;
629→};
630→
631→export async function acceptOrchestratorSession(
632→  input: AcceptSessionInput,
633→): Promise<AcceptSessionResult> {
634→  const lookup = await lookupSession(input.surreal, input.sessionId);
635→  if (!lookup.ok) {
636→    return { ok: false, error: lookup.error };
637→  }
638→  const { session, record: sessionRecord, status } = lookup;
639→
640→  if (!ACCEPTABLE_STATUSES.has(status)) {
641→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "accept") };
642→  }
643→
644→  const workspaceRecord = requireWorkspace(session, input.sessionId);
645→
646→  // 1. Update orchestrator_status to completed
647→  await input.surreal.update(sessionRecord).merge({
648→    orchestrator_status: "completed" as OrchestratorStatus,
649→  });
650→
651→  // 2. Clean up handle registry
652→  handleRegistry.delete(input.sessionId);
653→
654→  // 4. End the agent session
655→  await input.endAgentSession({
656→    surreal: input.surreal,
657→    workspaceRecord,
658→    sessionId: input.sessionId,
659→    summary: input.summary,
660→  });
661→
662→  return {
663→    ok: true,
664→    value: {
665→      accepted: true,
666→      sessionId: input.sessionId,
667→    },
668→  };
669→}
670→
671→// ---------------------------------------------------------------------------
672→// State guard helpers
673→// ---------------------------------------------------------------------------
674→
675→const REVIEWABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
676→const REJECTABLE_STATUSES = new Set<OrchestratorStatus>(["idle"]);
677→const ACCEPTABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
678→const PROMPTABLE_STATUSES = new Set<OrchestratorStatus>(["spawning", "active", "idle"]);
679→
680→function sessionStateConflict(sessionId: string, currentStatus: string, action: string): SessionError {
681→  return {
682→    code: "SESSION_ERROR",
683→    message: `Cannot ${action} session ${sessionId}: current status is ${currentStatus}`,
684→    httpStatus: 409,
685→  };
686→}
687→
688→function sessionAborted(sessionId: string): SessionError {
689→  return {
690→    code: "SESSION_ERROR",
691→    message: `Session ${sessionId} has been aborted`,
692→    httpStatus: 409,
693→  };
694→}
695→
696→// ---------------------------------------------------------------------------
697→// getOrchestratorReview
698→// ---------------------------------------------------------------------------
699→
700→type GetReviewInput = {
701→  surreal: Surreal;
702→  sessionId: string;
703→  getDiff: (repoRoot: string, branchName: string) => Promise<import("./worktree-manager").WorktreeResult<import("./worktree-manager").DiffResult>>;
704→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
705→  getTaskTitle: (taskId: string) => Promise<string>;
706→};
707→
708→export async function getOrchestratorReview(
709→  input: GetReviewInput,
710→): Promise<ReviewResult> {
711→  const lookup = await lookupSession(input.surreal, input.sessionId);
712→  if (!lookup.ok) {
713→    return { ok: false, error: lookup.error };
714→  }
715→  const { session, status } = lookup;
716→
717→  if (status === "aborted") {
718→    return { ok: false, error: sessionAborted(input.sessionId) };
719→  }
720→
721→  if (!REVIEWABLE_STATUSES.has(status)) {
722→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "review") };
723→  }
724→
725→  // Get diff from the branch
726→  const branchName = session.worktree_branch ?? "";
727→  const workspaceRecord = requireWorkspace(session, input.sessionId);
728→  const repoRoot = await input.resolveRepoRoot(workspaceRecord);
729→  const diffResult = await input.getDiff(repoRoot, branchName);
730→
731→  const diff = diffResult.ok
732→    ? diffResult.value
733→    : { files: [], rawDiff: "", stats: { filesChanged: 0, insertions: 0, deletions: 0 } };
734→
735→  // Get task title
736→  const taskId = session.task_id ? session.task_id.id : "";
737→  const taskTitle = taskId ? await input.getTaskTitle(taskId) : "";
738→
739→  return {
740→    ok: true,
741→    value: {
742→      taskTitle,
743→      diff,
744→      session: {
745→        orchestratorStatus: status,
746→        ...pickDefined({
747→          worktreeBranch: session.worktree_branch,
748→          startedAt: session.started_at,
749→          lastEventAt: session.last_event_at,
750→        }),
751→      },
752→    },
753→  };
754→}
755→
756→// ---------------------------------------------------------------------------
757→// rejectOrchestratorSession
758→// ---------------------------------------------------------------------------
759→
760→type RejectSessionInput = {
761→  surreal: Surreal;
762→  sessionId: string;
763→  feedback: string;
764→};
765→
766→export async function rejectOrchestratorSession(
767→  input: RejectSessionInput,
768→): Promise<RejectSessionResult> {
769→  const lookup = await lookupSession(input.surreal, input.sessionId);
770→  if (!lookup.ok) {
771→    return { ok: false, error: lookup.error };
772→  }
773→  const { session, record: sessionRecord, status } = lookup;
774→
775→  if (!REJECTABLE_STATUSES.has(status)) {
776→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "reject") };
777→  }
778→
779→  // 1. Update session status to active (agent resumes work)
780→  await input.surreal.update(sessionRecord).merge({
781→    orchestrator_status: "active" as OrchestratorStatus,
782→    last_feedback: input.feedback,
783→  });
784→
785→  // 2. Return task to in_progress
786→  if (session.task_id) {
787→    await input.surreal.update(session.task_id).merge({
788→      status: "in_progress",
789→      updated_at: new Date(),
790→    });
791→  }
792→
793→  return {
794→    ok: true,
795→    value: {
796→      rejected: true,
797→      continuing: true,
798→    },
799→  };
800→}
801→
802→// ---------------------------------------------------------------------------
803→// sendSessionPrompt
804→// ---------------------------------------------------------------------------
805→
806→type SendPromptInput = {
807→  surreal: Surreal;
808→  sessionId: string;
809→  text: string;
810→};
811→
812→export async function sendSessionPrompt(
813→  input: SendPromptInput,
814→): Promise<PromptSessionResult> {
815→  const lookup = await lookupSession(input.surreal, input.sessionId);
816→  if (!lookup.ok) {
817→    return { ok: false, error: lookup.error };
818→  }
819→  const { status } = lookup;
820→
821→  if (!PROMPTABLE_STATUSES.has(status)) {
822→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "prompt") };
823→  }
824→
825→  // The Claude Agent SDK uses a single query() call per conversation.
826→  // Follow-up prompts are not supported in this model.
827→  return {
828→    ok: false,
829→    error: {
830→      code: "SESSION_ERROR",
831→      message: `Follow-up prompts are not supported with the Agent SDK. Session ${input.sessionId} runs a single query() conversation.`,
832→      httpStatus: 409,
833→    },
834→  };
835→}
